refentry.refsect1:
&reftitle.description;
boolarray_all arrayarray callablecallback
array_all gibt &true; zurück, wenn die übergebene callback-Funktion für alle Elemente &true; zurückgibt. Andernfalls gibt die Funktion &false; zurück.

&reftitle.returnvalues;

 Die Funktion gibt &true; zurück, wenn callback für
 alle Elemente &true; zurückgibt. Andernfalls gibt die Funktion &false;
 zurück.

  &reftitle.examples;

   array_all-Beispiel


<?php
$array = [
    'a' => 'dog',
    'b' => 'cat',
    'c' => 'cow',
    'd' => 'duck',
    'e' => 'goose',
    'f' => 'elephant'
];

// Prüft, ob alle Tiernamen kürzer als 12 Buchstaben sind.
var_dump(array_all($array, function (string $value) {
    return strlen($value) < 12;
}));

// Prüft, ob alle Tiernamen länger als 5 Buchstaben sind.
var_dump(array_all($array, function (string $value) {
    return strlen($value) > 5;
}));

// Prüft, ob alle Array-Schlüssel Zeichenketten sind.
var_dump(array_all($array, function (string $value, $key) {
   return is_string($key);
}));
?>


   &example.outputs;


bool(true)
bool(false)
bool(true)
